// src/components/FormAluno.js
import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

function FormAluno({ onNovoAluno, alunoEditando, onFimEdicao }) {
  const { token } = useAuth();
  const fileInputRef = useRef(null);

  const [avatarFile, setAvatarFile] = useState(null);
  const [avatarPreview, setAvatarPreview] = useState('');
  const [nome, setNome] = useState('');
  const [ra, setRa] = useState('');
  const [periodoId, setPeriodoId] = useState('');
  const [usuario, setUsuario] = useState('');
  const [senha, setSenha] = useState('');
  const [role, setRole] = useState('aluno');
  const [mensagem, setMensagem] = useState('');
  const [periodos, setPeriodos] = useState([]);

  // Carrega períodos
  useEffect(() => {
    axios.get('/api/periodos', { withCredentials: true })
      .then(res => setPeriodos(res.data))
      .catch(() => setPeriodos([]));
  }, []);

  // Popula dados ao editar
  useEffect(() => {
    if (alunoEditando) {
      setNome(alunoEditando.nome || '');
      setRa(alunoEditando.ra || '');
      setPeriodoId(alunoEditando.periodo_id?.toString() || '');
      setUsuario(alunoEditando.usuario || '');
      setRole(alunoEditando.role || 'aluno');
      setAvatarPreview(alunoEditando.avatar_url || '');
      setAvatarFile(null);
      setSenha('');
    } else {
      setNome(''); setRa(''); setPeriodoId('');
      setUsuario(''); setRole('aluno'); setSenha('');
      setAvatarPreview(''); setAvatarFile(null);
    }
    setMensagem('');
  }, [alunoEditando]);

  const handleAvatarChange = e => {
    const file = e.target.files[0];
    if (file) {
      setAvatarFile(file);
      setAvatarPreview(URL.createObjectURL(file));
    }
  };

  const triggerFileSelect = () => fileInputRef.current.click();

  const validar = () => {
    if (nome.trim().split(' ').filter(p => p.length>=2).length <2) { setMensagem('Informe nome completo'); return false; }
    if (!/^\d{1,9}$/.test(ra)) { setMensagem('RA inválido'); return false; }
    if (!usuario.trim()) { setMensagem('Informe login'); return false; }
    if (!alunoEditando && senha.length <4) { setMensagem('Senha mín 4 caracteres'); return false; }
    if (!periodoId) { setMensagem('Selecione período'); return false; }
    return true;
  };

  const handleSubmit = async e => {
    e.preventDefault();
    setMensagem('');
    if (!validar()) return;

    const dados = { nome, ra, periodo_id: periodoId, usuario, role };
    if (!alunoEditando) dados.senha = senha;
    try {
      let alunoId;
      const config = {
        headers: { Authorization: `Bearer ${token}` },
        withCredentials: true
      };
      if (alunoEditando) {
        await axios.put(`/api/alunos/${alunoEditando.id}`, dados, config);
        alunoId = alunoEditando.id;
        setMensagem('Aluno atualizado com sucesso');
      } else {
        const res = await axios.post('/api/alunos', dados, config);
        alunoId = res.data.id;
        setMensagem('Aluno cadastrado com sucesso');
      }
      // upload avatar
      if (avatarFile) {
        const form = new FormData();
        form.append('avatar', avatarFile);
        await axios.post(
          '/api/alunos/avatar',
          form,
          { 
            headers: { 
              ...config.headers, 
              'Content-Type': 'multipart/form-data' 
            },
            withCredentials: true
          }
        );
      }
      // reset
      setNome(''); setRa(''); setPeriodoId(''); setUsuario(''); setSenha(''); setRole('aluno');
      setAvatarPreview(''); setAvatarFile(null);
      onNovoAluno();
      if (alunoEditando) onFimEdicao(); else setTimeout(()=>onFimEdicao&&onFimEdicao(),1500);
    } catch (err) {
      setMensagem(err.response?.data?.error || 'Erro ao salvar');
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <h2 className="text-xl font-bold">
        {alunoEditando ? 'Editar Aluno' : 'Cadastrar Novo Aluno'}
      </h2>

      {/* Avatar */}
      <div className="flex justify-center">
        <div onClick={triggerFileSelect} className="w-24 h-24 rounded-full overflow-hidden cursor-pointer">
          <img
            src={avatarPreview || '/default-avatar.png'}
            alt="Avatar"
            className="w-full h-full object-cover"
          />
        </div>
        <input
          ref={fileInputRef}
          type="file"
          accept="image/*"
          onChange={handleAvatarChange}
          className="hidden"
        />
      </div>

      {/* Campos */}
      <div>
        <label className="block mb-1">Nome Completo</label>
        <input className="w-full border rounded px-3 py-2" value={nome} onChange={e=>setNome(e.target.value)} />
      </div>
      <div>
        <label className="block mb-1">RA</label>
        <input className="w-full border rounded px-3 py-2" value={ra} onChange={e=>setRa(e.target.value.replace(/\D/g,'').slice(0,9))} maxLength={9} />
      </div>
      <div>
        <label className="block mb-1">Período</label>
        <select className="w-full border rounded px-3 py-2" value={periodoId} onChange={e=>setPeriodoId(e.target.value)}>
          <option value="">Selecione</option>
          {periodos.map(p=><option key={p.id} value={p.id}>{p.nome} ({p.turno})</option>)}
        </select>
      </div>
      <div>
        <label className="block mb-1">Login</label>
        <input className="w-full border rounded px-3 py-2" value={usuario} onChange={e=>setUsuario(e.target.value)} />
      </div>
      <div>
        <label className="block mb-1">Senha</label>
        <input type="password" className="w-full border rounded px-3 py-2" value={senha} onChange={e=>setSenha(e.target.value)} />
      </div>
      <div>
        <label className="block mb-1">Permissão</label>
        <select className="w-full border rounded px-3 py-2" value={role} onChange={e=>setRole(e.target.value)}>
          <option value="aluno">Aluno</option>
          <option value="recepcao">Recepção</option>
        </select>
      </div>

      <div className="flex gap-4">
        <button type="submit" className="bg-blue-600 text-white py-2 px-4 rounded">{alunoEditando ? 'Atualizar' : 'Cadastrar'}</button>
        {alunoEditando && <button type="button" onClick={onFimEdicao} className="bg-gray-300 py-2 px-4 rounded">Cancelar</button>}
      </div>
      {mensagem && <p className="mt-2 text-red-600">{mensagem}</p>}
    </form>
  );
}

export default FormAluno;
